agent_output:
{
  "domain_analysis": {
    "business_context": "Evolution of the Shipment aggregate from a 1:1 Shipment-Recipient relationship to a 1:N relationship. This is a fundamental change to the core domain model of a delivery platform, affecting the Shipment aggregate root boundary, all downstream processes (routing, delivery, notification, billing), and external integrations. This is not a simple schema migration — it redefines what a Shipment *is*.",
    "bounded_context": "Shipment Management / Order Fulfillment",
    "ubiquitous_language": [
      { "term": "Shipment", "definition": "A unit of goods in transit from origin to one or more destinations. Post-change, a Shipment is a logical grouping that may require multiple delivery stops." },
      { "term": "Recipient", "definition": "A person or entity receiving a delivery, identified by name, address, phone number, and (new) delivery preferences." },
      { "term": "Delivery Preference", "definition": "Recipient-specific instructions governing how and when delivery should occur (e.g., time window, safe place, signature requirement, contactless delivery)." },
      { "term": "Primary Recipient", "definition": "PROPOSED: The first or default recipient on a multi-recipient shipment. Critical for backward compatibility and for processes that require a single point of contact." },
      { "term": "Delivery Stop", "definition": "A discrete delivery event within a multi-recipient shipment. Each stop targets one Recipient at one address." },
      { "term": "Shipment Status", "definition": "The lifecycle state of the shipment. Previously a single linear progression; now potentially a composite status requiring per-recipient tracking." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "A Shipment MUST have at least one Recipient at all times.",
      "invariant": true,
      "invariant_justification": "A shipment with zero recipients has no destination and is physically undeliverable. This is a data integrity constraint — the system is corrupt if violated.",
      "testable_assertion": "shipment.recipients.length >= 1 must hold true at every state transition of the Shipment lifecycle."
    },
    {
      "id": "BR-2",
      "rule": "Each Recipient on a Shipment MUST have a valid name, address, and phone number.",
      "invariant": true,
      "invariant_justification": "These are the minimum fields required for physical delivery and legally required contact. Without them, a courier cannot complete delivery.",
      "testable_assertion": "For every recipient R in shipment.recipients: R.name is non-empty, R.address passes address validation, R.phone is a valid phone number."
    },
    {
      "id": "BR-3",
      "rule": "Each Recipient on a Shipment MAY have independent delivery preferences. If none are specified, system defaults apply.",
      "invariant": false,
      "invariant_justification": "Delivery preferences are a business policy layer. Defaults can change without corrupting data integrity.",
      "testable_assertion": "A Recipient without explicit delivery preferences receives the platform's default delivery behavior."
    },
    {
      "id": "BR-4",
      "rule": "Shipment status must reflect the aggregate delivery state across ALL recipients. A Shipment is only 'Delivered' when ALL recipients have received their delivery.",
      "invariant": true,
      "invariant_justification": "Marking a shipment as delivered when one recipient has not received their goods is a state integrity violation — it misrepresents physical reality and triggers incorrect downstream events (billing, SLA timers).",
      "testable_assertion": "shipment.status == 'Delivered' implies ALL shipment.recipients[*].deliveryStatus == 'Delivered'."
    },
    {
      "id": "BR-5",
      "rule": "Removing the last Recipient from a Shipment is prohibited. The operation must be rejected.",
      "invariant": true,
      "invariant_justification": "Corollary to BR-1. Preventing removal that would violate the minimum-one-recipient invariant.",
      "testable_assertion": "An attempt to remove a recipient when shipment.recipients.length == 1 returns an error and does not mutate state."
    },
    {
      "id": "BR-6",
      "rule": "All existing single-recipient shipments must remain valid and fully functional after migration without any data loss or behavioral change.",
      "invariant": true,
      "invariant_justification": "2 million production shipments represent real-world obligations. Corrupting or altering their behavior violates contractual and operational integrity.",
      "testable_assertion": "For every pre-migration shipment S: S has exactly 1 recipient, all fields are preserved, all API responses for S are identical pre- and post-migration."
    },
    {
      "id": "BR-7",
      "rule": "External partner APIs must continue to receive shipment data in the current single-recipient format for existing integrations, unless partners explicitly opt into the new format.",
      "invariant": false,
      "invariant_justification": "This is a contractual/partnership policy. Partners can be migrated over time, but the policy itself is changeable by agreement.",
      "testable_assertion": "Partner API payloads for non-opted-in partners contain a single 'recipient' object (not an array). For multi-recipient shipments sent to legacy partners, the primary recipient is used."
    },
    {
      "id": "BR-8",
      "rule": "Adding or removing Recipients from an in-transit Shipment requires re-routing and must not violate delivery SLAs for existing Recipients on that Shipment.",
      "invariant": false,
      "invariant_justification": "SLA thresholds are business policy. But the rule that mid-flight changes trigger re-routing is operationally critical.",
      "testable_assertion": "When a recipient is added to a shipment with status 'InTransit', a re-route event is emitted and existing recipient SLA deadlines are not shortened."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A new Shipment is being created",
      "when": "The requester provides two or more Recipients with distinct addresses and delivery preferences",
      "then": "The Shipment is created with all Recipients, each retaining their individual preferences, and the Shipment status is initialized correctly"
    },
    {
      "id": "AC-2",
      "given": "An existing single-recipient Shipment created before migration",
      "when": "The Shipment is retrieved via API",
      "then": "The response is backward-compatible: the single recipient is accessible, all original fields are intact, and no data has been lost"
    },
    {
      "id": "AC-3",
      "given": "A multi-recipient Shipment where Recipient A has been delivered but Recipient B has not",
      "when": "The Shipment status is queried",
      "then": "The Shipment status is 'Partially Delivered' (or equivalent composite state), NOT 'Delivered'"
    },
    {
      "id": "AC-4",
      "given": "A Shipment with exactly one Recipient",
      "when": "A request is made to remove that Recipient",
      "then": "The request is rejected with a clear error; the Shipment remains unchanged"
    },
    {
      "id": "AC-5",
      "given": "An external partner integration that has NOT opted into the new format",
      "when": "A multi-recipient Shipment's data is sent to that partner",
      "then": "The partner receives a single-recipient payload using the primary recipient, with no breaking schema changes"
    },
    {
      "id": "AC-6",
      "given": "A Shipment with 2 million existing records in production",
      "when": "The data migration is executed",
      "then": "All 2 million shipments are queryable as single-recipient shipments, no records are lost, and rollback is possible within the migration window"
    },
    {
      "id": "AC-7",
      "given": "A multi-recipient Shipment",
      "when": "Each Recipient specifies different delivery preferences (e.g., one requires signature, another allows safe-place)",
      "then": "Each delivery stop honors the individual Recipient's preferences independently"
    },
    {
      "id": "AC-8",
      "given": "A Shipment is in-transit with Recipients A and B",
      "when": "Recipient C is added mid-transit",
      "then": "A re-route event is emitted, Recipient C is added, and existing SLA commitments for A and B are not degraded"
    }
  ],

  "edge_cases": [
    {
      "scenario": "Multi-recipient Shipment where two Recipients share the same address",
      "expected_behavior": "Both Recipients are retained as separate entities (they may be different people at the same address). The courier makes one stop but fulfills two delivery obligations with potentially different preferences."
    },
    {
      "scenario": "Recipient is added to a Shipment that has already been marked 'Delivered' for all existing recipients",
      "expected_behavior": "This should either be rejected (shipment lifecycle is closed) or the shipment reverts to a non-terminal state. Business must decide — this is an escalation point."
    },
    {
      "scenario": "External partner receives a multi-recipient shipment but only supports single-recipient format — which recipient is 'primary'?",
      "expected_behavior": "The system must have a deterministic rule for selecting the primary recipient (e.g., first added, explicitly flagged). This cannot be ambiguous or random."
    },
    {
      "scenario": "One Recipient on a multi-recipient Shipment refuses delivery",
      "expected_behavior": "That Recipient's delivery status becomes 'Refused'. The Shipment is not 'Delivered' until all recipients reach a terminal state (Delivered, Refused, or Failed). Return logistics may be triggered for the refused portion."
    },
    {
      "scenario": "Billing: is a multi-recipient shipment billed as one shipment or N deliveries?",
      "expected_behavior": "This is a critical business decision that affects revenue. The billing model must be explicitly defined — per-shipment, per-recipient, or per-stop. Cannot be left ambiguous."
    },
    {
      "scenario": "Concurrent modification: two users add/remove recipients on the same shipment simultaneously",
      "expected_behavior": "Optimistic concurrency control must prevent the invariant (>= 1 recipient) from being violated. The second conflicting operation fails and must be retried."
    },
    {
      "scenario": "Migration rollback: after partial migration, a rollback is needed",
      "expected_behavior": "Any shipments that were created as multi-recipient post-migration must be handled. Rollback plan must account for new multi-recipient data that has no representation in the old schema."
    }
  ],

  "business_impact": {
    "financial": "HIGH. Multi-recipient shipments likely change the billing model (per-shipment vs per-stop). If pricing is not explicitly redefined, revenue leakage or customer overcharging will occur. Migration cost is non-trivial for 2M records. Partner API changes require coordination budget.",
    "operational": "HIGH. Route optimization algorithms must be reworked — a shipment is no longer origin→destination but origin→[stop1, stop2, ...stopN]. Courier dispatch, SLA tracking, and delivery confirmation workflows all change fundamentally. The 'Partially Delivered' status is a new operational state that support teams must be trained on.",
    "user": "MEDIUM-HIGH. Customers gain the ability to send to multiple recipients in one shipment (convenience, potential cost savings). However, tracking UX becomes more complex — 'Where is my package?' now has per-recipient answers. Notification logic must be per-recipient.",
    "risk": "HIGH. This is a structural change to the core aggregate. Risks include: data migration failure on 2M records, breaking external partner integrations, introducing a 'Partially Delivered' state that existing monitoring/alerting doesn't handle, billing model ambiguity causing revenue impact, and increased domain complexity leading to bugs in delivery status computation.",
    "stakeholders_affected": [
      { "group": "Customers (Senders)", "impact": "Gain multi-recipient capability. Must understand new pricing. UX for managing multiple recipients must be intuitive." },
      { "group": "Customers (Recipients)", "impact": "Each recipient gets individual tracking and delivery preferences. Notification experience changes." },
      { "group": "Couriers / Drivers", "impact": "Route changes. A single shipment now means multiple stops. Delivery confirmation flow becomes per-stop. Workload estimation changes." },
      { "group": "External Partners", "impact": "API contract changes. Partners must either accept a new payload format or be shielded by backward-compatible mapping. Both have cost." },
      { "group": "Finance / Billing", "impact": "Billing model must be redefined. Multi-recipient shipments need a clear pricing structure before launch." },
      { "group": "Customer Support", "impact": "New 'Partially Delivered' state creates new support scenarios. Agents need training and updated playbooks." },
      { "group": "Engineering / Platform", "impact": "Schema migration on 2M records, API versioning, event schema changes, route optimization rework, status computation logic overhaul." }
    ]
  },

  "confidence": {
    "level": 52,
    "reasoning": "The spec describes WHAT changes (1:1 → 1:N recipients) but leaves several critical business decisions undefined: billing model, primary recipient selection rule, whether mid-lifecycle recipient changes are allowed, what 'delivery preferences' specifically includes, and the partner migration strategy. These are not implementation details — they are business-defining decisions that change the acceptance criteria materially. The 2M record migration adds operational risk that requires a defined rollback strategy not present in the spec.",
    "high_confidence_areas": [
      "The minimum-one-recipient invariant is universal in logistics",
      "Backward compatibility for 2M existing records is non-negotiable",
      "External partner APIs need a compatibility layer",
      "Shipment status must become composite (per-recipient tracking)"
    ],
    "low_confidence_areas": [
      "Billing model for multi-recipient shipments is completely undefined",
      "Primary recipient selection rule for legacy API compatibility is not specified",
      "Whether recipients can be added/removed mid-transit is not clarified",
      "The exact scope of 'delivery preferences' is unspecified",
      "Whether 'Partially Delivered' is a formal status or derived is not stated"
    ],
    "assumptions": [
      "The existing 'recipient' field will be migrated to a 'recipients' collection with one element per legacy shipment",
      "A concept of 'primary recipient' will be needed for backward compatibility even if not in the spec",
      "Delivery preferences include at minimum: time window, signature requirement, and safe-place authorization",
      "The migration must be zero-downtime given production scale"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "The billing model for multi-recipient shipments is not defined. Is a 3-recipient shipment billed as 1 shipment, 3 deliveries, or by distance/stops? This fundamentally changes the product's value proposition and revenue model.",
      "affected_stakeholders": ["Finance / Billing", "Customers (Senders)", "Product"],
      "options": ["Bill per shipment (flat rate regardless of recipients)", "Bill per recipient/stop (additive pricing)", "Bill per shipment with per-stop surcharge (hybrid)"],
      "recommendation": "Hybrid model — base shipment fee plus per-additional-stop surcharge. Aligns incentives: customers still benefit from bundling, platform captures marginal delivery cost."
    },
    {
      "type": "ambiguity",
      "description": "'Delivery preferences' is referenced but never enumerated. The domain model cannot be finalized without knowing the exact set of preferences, which ones are per-recipient vs per-shipment, and their valid values.",
      "affected_stakeholders": ["Product", "Customers (Recipients)", "Couriers / Drivers"],
      "options": ["Define a minimal set (time window, signature, safe-place) and extend later", "Survey existing delivery preference usage and replicate per-recipient", "Leave as free-form key-value pairs"],
      "recommendation": "Define a minimal explicit set based on existing platform capabilities. Free-form preferences create validation nightmares and courier confusion."
    },
    {
      "type": "missing_context",
      "description": "No primary recipient selection rule is defined, but one is required for backward-compatible partner API payloads and for any process that needs a single point of contact (e.g., customs declarations, insurance claims).",
      "affected_stakeholders": ["External Partners", "Engineering / Platform", "Legal / Compliance"],
      "options": ["First recipient added is primary", "Sender explicitly designates primary", "Recipient at first delivery stop is primary"],
      "recommendation": "Sender explicitly designates primary at shipment creation, defaulting to the first recipient if not specified. Explicit is better than implicit for a field this consequential."
    },
    {
      "type": "missing_context",
      "description": "No guidance on whether recipients can be added or removed after shipment is in-transit. This affects routing, SLA commitments, and courier workflows. It is not an edge case — it will happen in production.",
      "affected_stakeholders": ["Couriers / Drivers", "Customers (Senders)", "Operations"],
      "options": ["Allow modifications only before pickup", "Allow modifications at any non-terminal state with re-routing", "Allow additions only (no removals) during transit"],
      "recommendation": "Allow additions and removals before pickup freely. After pickup, allow additions only with re-route and SLA re-calculation. Removals mid-transit are operationally dangerous (goods already loaded) and should be prohibited."
    }
  ],

  "rejection_reasons": []
}

